// Parse LLM response and build account memo
const raw = items[0].json.response || 
            items[0].json.choices?.[0]?.message?.content || '';

let memo = {};
try {
  const cleaned = raw.replace(/```json|```/g, '').trim();
  memo = JSON.parse(cleaned);
} catch(e) {
  // Rule-based fallback for critical fields
  memo = {
    company_name: null,
    business_hours: { days: null, start: null, end: null, timezone: null },
    emergency_definition: [],
    emergency_routing_rules: { primary_phone: null, fallback: null },
    questions_or_unknowns: ['LLM parsing failed - manual review required'],
    notes: 'Fallback extraction'
  };
}

// Add metadata
const accountId = $input.first().json.account_id || 
  'ACC_' + Date.now().toString(36).toUpperCase();

memo.account_id = accountId;
memo.version = 'v1';
memo.created_at = new Date().toISOString();
memo.pipeline_source = 'demo_call';

return [{ json: { memo, account_id: accountId } }];

// Generate Retell Agent Spec from memo
const memo = items[0].json.memo;
const accountId = items[0].json.account_id;

const bh = memo.business_hours || {};
const routing = memo.emergency_routing_rules || {};
const transfer = memo.call_transfer_rules || {};
const company = memo.company_name || 'the company';

const agentSpec = {
  agent_name: `Clara - ${company} (v1)`,
  account_id: accountId,
  version: 'v1',
  created_at: new Date().toISOString(),
  voice_style: {
    provider: 'elevenlabs',
    voice_id: 'rachel',
    style: 'professional'
  },
  key_variables: {
    timezone: bh.timezone || '[TIMEZONE_REQUIRED]',
    business_hours_days: bh.days || '[DAYS_REQUIRED]',
    business_hours_start: bh.start || '[START_REQUIRED]',
    business_hours_end: bh.end || '[END_REQUIRED]',
    emergency_primary_phone: routing.primary_phone || '[PHONE_REQUIRED]',
    company_name: company
  },
  call_transfer_protocol: {
    timeout_seconds: transfer.timeout_seconds || 60,
    method: 'warm_transfer',
    on_fail: transfer.on_fail_message || 'I was unable to reach our team. Someone will call you back shortly.'
  },
  retell_config_notes: {
    begin_message: `Thank you for calling ${company}. This is Clara. How can I help you today?`,
    language: 'en-US',
    max_call_duration_seconds: 600
  }
};

return [{ json: { memo, agent_spec: agentSpec, account_id: accountId } }];

// Write memo and spec to outputs directory
const fs = require('fs');
const path = require('path');

const { memo, agent_spec, account_id } = items[0].json;

const outputDir = path.join('/home/user/clara-automation/outputs/accounts', account_id, 'v1');
fs.mkdirSync(outputDir, { recursive: true });

fs.writeFileSync(path.join(outputDir, 'memo.json'), JSON.stringify(memo, null, 2));
fs.writeFileSync(path.join(outputDir, 'agent_spec.json'), JSON.stringify(agent_spec, null, 2));

return [{ json: { 
  status: 'saved',
  account_id,
  memo_path: path.join(outputDir, 'memo.json'),
  spec_path: path.join(outputDir, 'agent_spec.json')
}}];

// Pipeline B: Merge onboarding into v1 and produce v2
const fs = require('fs');
const path = require('path');

const { account_id, onboarding_data } = items[0].json;

// Load v1
const v1Path = path.join('/home/user/clara-automation/outputs/accounts', account_id, 'v1', 'memo.json');
if (!fs.existsSync(v1Path)) {
  return [{ json: { status: 'error', reason: 'v1_not_found', account_id } }];
}

const v1 = JSON.parse(fs.readFileSync(v1Path, 'utf8'));
const v2 = JSON.parse(JSON.stringify(v1)); // deep clone

// Smart merge: only override non-null values
function smartMerge(target, source) {
  for (const [k, v] of Object.entries(source)) {
    if (['_extraction_method','created_at','version','pipeline_source','account_id'].includes(k)) continue;
    if (v === null || v === undefined) continue;
    if (Array.isArray(v) && v.length === 0) continue;
    if (typeof v === 'object' && !Array.isArray(v) && typeof target[k] === 'object') {
      smartMerge(target[k], v);
    } else {
      target[k] = v;
    }
  }
}

smartMerge(v2, onboarding_data);
v2.version = 'v2';
v2.updated_at = new Date().toISOString();

// Compute diff
const changes = [];
function diff(o, n, p='') {
  const keys = new Set([...Object.keys(o), ...Object.keys(n)]);
  for (const k of keys) {
    const fp = p ? `${p}.${k}` : k;
    if (['_extraction_method','created_at','version','updated_at'].includes(k)) continue;
    if (JSON.stringify(o[k]) !== JSON.stringify(n[k])) {
      if (typeof o[k] === 'object' && typeof n[k] === 'object' && o[k] && n[k]) {
        diff(o[k], n[k], fp);
      } else {
        changes.push({ field: fp, old_value: o[k], new_value: n[k] });
      }
    }
  }
}
diff(v1, v2);

return [{ json: { v1, v2, changes, account_id } }];

// Save v2 and generate changelog
const fs = require('fs');
const path = require('path');

const { v2, changes, account_id } = items[0].json;

const v2Dir = path.join('/home/user/clara-automation/outputs/accounts', account_id, 'v2');
fs.mkdirSync(v2Dir, { recursive: true });

fs.writeFileSync(path.join(v2Dir, 'memo.json'), JSON.stringify(v2, null, 2));

// Generate changelog markdown
const lines = [
  `# Changelog: ${account_id}`,
  `## v1 → v2`,
  `Generated: ${new Date().toISOString()}`,
  `Total changes: ${changes.length}`,
  '',
  '## Changes',
  ''
];
for (const c of changes) {
  lines.push(`### \`${c.field}\``);
  lines.push(`- Before: \`${c.old_value}\``);
  lines.push(`- After: \`${c.new_value}\``);
  lines.push('');
}

fs.writeFileSync(path.join(v2Dir, 'changes.md'), lines.join('\n'));
fs.writeFileSync(path.join(v2Dir, 'changes.json'), JSON.stringify({ account_id, changes }, null, 2));

return [{ json: { status: 'success', account_id, change_count: changes.length } }];
